    even_idx = 0
    odd_idx = 0
    for order in orders:
        y_vals = data_right[order]
        
        if order % 2 == 0:
            color = even_colors[even_idx]
            linestyle = '--' 
            even_idx += 1
        else:
            color = odd_colors[odd_idx]
            linestyle = '-'   
            odd_idx += 1
        
        lw = 1.0
        alpha = 0.85
        
        ax.plot(g_list_right, y_vals, 
                color=color, 
                linewidth=lw, 
                alpha=alpha,
                linestyle=linestyle)
    
    g_target = 2.8
    idx_g = np.argmin(np.abs(g_list_right - g_target))
    
    orders_inset = list(range(2, 11))
    ecorr_at_g = [data_right[order][idx_g] for order in orders_inset]
    fci_at_g = data_right[0][idx_g]
    
    axins = inset_axes(ax, width="40%", height="35%", loc='lower left',
                      bbox_to_anchor=(0.1, 0.02, 1.2, 1), bbox_transform=ax.transAxes)
    
    even_idx = 0
    odd_idx = 0
    for i, order in enumerate(orders_inset):
        if order % 2 == 0:
            color = even_colors[even_idx]
            marker = 's' 
            even_idx += 1
        else:
            color = odd_colors[odd_idx]
            marker = 'o' 
            odd_idx += 1
        axins.plot(order, ecorr_at_g[i], marker=marker, color=color, 
                  markersize=3.5, markeredgewidth=0.5, markeredgecolor='black')
    
    axins.axhline(fci_at_g, color='k', linestyle='--', linewidth=0.8, alpha=1)
    
    gray_orders = list(range(2, 11))
    gray_ecorr = [ecorr_at_g[i] if i <= 4 else ecorr_at_g[4] for i in range(len(orders_inset))]  
    axins.plot(gray_orders, gray_ecorr, color='gray', linestyle='-', linewidth=1.0, alpha=0.6)
    
